package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Constructor;

class CSVFormatTest {

    @Test
    void testGetQuoteMode_NonNull() throws Exception {
        QuoteMode mode = QuoteMode.ALL;

        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class,
                Character.class,
                QuoteMode.class,
                Character.class,
                Character.class,
                boolean.class,
                boolean.class,
                String.class,
                String.class,
                String[].class,
                boolean.class,
                boolean.class);
        constructor.setAccessible(true);

        CSVFormat format = constructor.newInstance(
                ',',
                '"',
                mode,
                null,
                null,
                false,
                false,
                "\r\n",
                null,
                (Object) null,
                false,
                false);
        assertEquals(mode, format.getQuoteMode());
    }

    @Test
    void testGetQuoteMode_Null() throws Exception {
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class,
                Character.class,
                QuoteMode.class,
                Character.class,
                Character.class,
                boolean.class,
                boolean.class,
                String.class,
                String.class,
                String[].class,
                boolean.class,
                boolean.class);
        constructor.setAccessible(true);

        CSVFormat format = constructor.newInstance(
                ',',
                '"',
                null,
                null,
                null,
                false,
                false,
                "\r\n",
                null,
                (Object) null,
                false,
                false);
        assertNull(format.getQuoteMode());
    }

    @Test
    void testGetQuoteMode_DefaultConstant() {
        assertNotNull(CSVFormat.DEFAULT.getQuoteMode());
    }

    @Test
    void testGetQuoteMode_WithQuoteModeViaWithQuoteMode() {
        CSVFormat format = CSVFormat.DEFAULT.withQuoteMode(QuoteMode.MINIMAL);
        assertEquals(QuoteMode.MINIMAL, format.getQuoteMode());
    }
}
